    createManual: 'Create Manual Task',
    weeklyDesc: 'Define standard operations for each day. These blueprints can be synchronized to your daily schedule instantly.',
    syncToToday: 'Sync to Today', blueprint: 'Blueprint', noOps: 'No standard operations defined',
    addBlueprint: 'Add Blueprint Block',
    slams30: '30-Day Slams', currentStreak: 'Current Streak', heatmap: 'Heatmap (Last 30 Days)',
    install: 'Installation', addWorkspace: 'Add to Workspace',
    iosStep1: "Tap the 'Share' icon in the Safari toolbar.",
    iosStep2: "Scroll and select 'Add to Home Screen'.",
    androidStep1: "Tap the menu icon (three dots) in Chrome.",
    androidStep2: "Select 'Install App' or 'Add to Home Screen'.",
    visitMsg: 'Please visit this app on iOS Safari or Android Chrome to install as a PWA desktop application.',
    clearStorage: 'Clear Local Storage', language: 'Language Switch', langLabel: 'Switch between EN / ZH',
    taskIdentity: 'Task Identity', startBlock: 'Start Block', endBlock: 'End Block',
    terminate: 'Terminate Task', cancel: 'Cancel', save: 'Save', newTask: 'New Task', editTask: 'Edit Task',
    opStatus: 'Operational Status', completed100: '100% Completed'
  },
  zh: {
    navDaily: '鏃ョ▼', navWeekly: '鍛ㄦā鏉?, navGrid: '鎴愬氨', navPWA: '璁剧疆',
    titleSchedule: '浠婃棩鏃ョ▼', titleWeekly: '鍛ㄦā鏉块厤缃?, titleAchievements: '鎴愬氨缁熻', titleSettings: '绯荤粺璁剧疆',
    status: '褰撳墠鐘舵€?, grandSlam: '鍏ㄦ弧璐?, active: '杩涜涓?, completion: '瀹屾垚杩涘害',
    syncTemplate: '鍚屾鍛ㄦā鏉?, pullTemplate: '浠庡懆妯℃澘瀵煎叆浠婃棩浠诲姟',
    createManual: '鎵嬪姩鍒涘缓浠诲姟',
    weeklyDesc: '瀹氫箟姣忓ぉ鐨勬爣鍑嗗伐浣滄祦銆傝繖浜涙ā鏉垮彲浠ヤ竴閿悓姝ュ埌浣犵殑姣忔棩鏃ョ▼涓€?,
    syncToToday: '鍚屾鑷充粖鏃?, blueprint: '鏍囧噯宸ヤ綔娴?, noOps: '鏈畾涔夋爣鍑嗗伐浣滄祦',
    addBlueprint: '娣诲姞宸ヤ綔娴佸尯鍧?,
    slams30: '杩?0澶╂弧璐?, currentStreak: '褰撳墠杩炵画杈炬爣', heatmap: '娲诲姩鐑姏鍥?(杩?0澶?',
    install: '瀹夎鎸囧崡', addWorkspace: '娣诲姞鑷充富灞忓箷 (PWA)',
    iosStep1: "鐐瑰嚮 Safari 搴曢儴瀵艰埅鏍忕殑銆屽叡浜€嶅浘鏍囥€俓

bg-[#F9F9FB] flex justify-between items-center w-full px-6 py-5 sticky top-0 z-40 border-b border-[#1D1D1F]/10">
    <h1 className="font-['Inter'] font-black tracking-tight uppercase text-lg text-[#1D1D1F]">{title}</h1>
    {extraText && <div className="text-xl font-black tracking-tighter text-[#1D1D1F]">{extraText}</div>}
  </header>
);

const BottomNav = () => {
  const { currentView, setView, language } = useStore();
  const t = i18n[language];
  const navItems: { id: ViewType; icon: React.ElementType; label: string }[] = [
    { id: 'SCHEDULE', icon: CalendarDays, label: t.navDaily },
    { id: 'WEEKLY', icon: LayoutTemplate, label: t.navWeekly },
    { id: 'ACHIEVEMENTS', icon: Calendar, label: t.navGrid },
    { id: 'SETTINGS', icon: Settings, label: t.navPWA },
  ];

  return (
    <nav className="fixed bottom-0 left-0 w-full h-16 flex justify-around items-stretch bg-[#F9F9FB]/90 backdrop-blur-md z-40 border-t border-[#1D1D1F]/10">
      {navItems.map(item => {
        const Icon = item.icon;
        const isActive = currentView === item.id;
        return (
          <button 
            key={item.id} onClick={() => setView(item.id)}
            className={`flex flex-col items-center justify-center h-full w-full transition-colors border-t-2 rounded-none ${isActive ? 'bg-[#1D1D1F] text-[#F9F9FB] border-[#1D1D1F]' : 'text-[#1D1D1F]/50 border-transparent hover:bg-[#1D1D1F]/5'}`}
          >
            <Icon size={20} strokeWidth={isActive ? 3 : 2} className="mb-1" />
            <span className="font-['Inter'] text-[9px] uppercase tracking-widest font-black">{item.label}</span>
          </button>
        );
      })}
    </nav>
  );
};

const GrandSlamEffect = () => {
  const { language } = useStore();
  const t = i18n[language];

  return (
    <motion.div 
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={{ opacity: 0 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      className="fixed inset-0 z-[100] bg-[#72FF70] flex flex-col items-center justify-center p-6"
    >
      <motion.div
        initial={{ y: 20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ delay: 0.2, duration: 0.5 }}
        className="text-center mix-blend-difference text-white"
      >
        <span className="font-['Inter'] text-sm uppercase tracking-[0.5em] font-bold block mb-4">{t.opStatus}</span>
        <h1 className="text-6xl md:text-8xl font-black tracking-tighter uppercase leading-none">GRAND<br/>SLAM</h1>
        <p className="mt-8 text-xl font-bold uppercase tracking-widest">{t.completed100}</p>
      </motion.div>
    </motion.div>
  );
};

// ==========================================
// 4. 鏍稿績瑙嗗浘缁勪欢
// ==========================================

// --- View A: 姣忔棩浠诲姟瑙嗗浘 (Schedule Timeline) ---
const ViewSchedule = () => {
  const { currentDate, plans, toggleTaskStatus, setEditingTask, syncWeeklyTemplate, language } = useStore();
  const t = i18n[language];
  const plan = plans[currentDate] || { tasks: [], isGrandSlam: false };
  const total = plan.tasks.length;
  const completed = plan.tasks.filter(t => t.status === 'COMPLETED').length;
  const progressPercent = total === 0 ? 0 : (completed / total) * 100;

  return (
    <div className="pb-32 min-h-screen">
      <TopBar title={t.titleSchedule} extraText={currentDate.replace(/-/g, '.')} />

      <main className="px-6 pt-12 max-w-2xl mx-auto space-y-16">
        {/* Progress Metrics */}
        <section className="flex flex-col gap-6">
          <div className="space-y-1">
            <span className="font-['Inter'] text-[10px] font-bold uppercase tracking-widest text-[#1D1D1F]/50">{t.status}</span>
            <h2 className="text-5xl font-black tracking-tighter text-[#1D1D1F] uppercase">
              {plan.isGrandSlam ? t.grandSlam : t.active}
            </h2>
          </div>
          <div className="w-full">
            <div className="flex justify-between items-end mb-2 font-['Inter'] text-xs font-bold uppercase tracking-widest text-[#1D1D1F]">
              <span>{t.completion}</span>
              <span>{completed} / {total}</span>
            </div>
            <div className="w-full h-1 bg-[#1D1D1F]/10 relative">
              <div 
                className={`absolute inset-y-0 left-0 transition-all duration-700 ease-out ${plan.isGrandSlam ? 'bg-[#72FF70]' : 'bg-[#1D1D1F]'}`} 
                style={{ width: `${progressPercent}%` }}
              />
            </div>
          </div>
        </section>

        {/* Sync Intent (If Empty) */}
        {total === 0 && (
          <button 
            onClick={() => syncWeeklyTemplate(currentDate)}
            className="w-full p-8 bg-[#1D1D1F] text-[#F9F9FB] flex flex-col items-center justify-center hover:bg-[#1D1D1F]/90 transition-colors"
          >
            <Download size={32} className="mb-4" />
            <span className="font-['Inter'] font-black text-xl uppercase tracking-tight">{t.syncTemplate}</span>
            <span className="font-['Inter'] text-xs tracking-widest uppercase mt-2 opacity-60">{t.pullTemplate}</span>
          </button>
        )}

        {/* Timeline Blade */}
        <div className="relative">
          <div className="absolute left-[3.5rem] top-0 bottom-0 w-[2px] bg-[#1D1D1F]/10 hidden sm:block" />

          <div className="space-y-6 relative">
            {plan.tasks.map((task) => {
              const isCompleted = task.status === 'COMPLETED';
              return (
                <div key={task.id} className="group flex items-start gap-4 sm:gap-8 w-full">
                  <div className="w-14 shrink-0 text-right pt-2">
                    <span className={`font-['Inter'] text-xs font-black uppercase tracking-tighter ${isCompleted ? 'text-[#1D1D1F]/30' : 'text-[#1D1D1F]'}`}>
                      {task.startTime}
                    </span>
                  </div>

                  <div 
                    className={`relative grow flex items-start gap-4 p-5 sm:p-6 cursor-pointer transition-all duration-300 border-l-[3px]
                      ${isCompleted ? 'bg-[#1D1D1F]/5 border-[#1D1D1F]/20' : 'bg-[#FFFFFF] border-[#1D1D1F] hover:bg-[#1D1D1F]/5'}`}
                    onClick={() => setEditingTask({ context: 'DAILY', task })}
                  >
                    <button 
                      className="pt-1 shrink-0" 
                      onClick={(e) => { e.stopPropagation(); toggleTaskStatus(currentDate, task.id); }}
                    >
                      {isCompleted ? (
                        <div className="w-6 h-6 bg-[#1D1D1F] flex items-center justify-center">
                          <Check size={16} strokeWidth={4} color="#F9F9FB" />
                        </div>
                      ) : (
                        <div className="w-6 h-6 border-[2px] border-[#1D1D1F] bg-transparent" />
                      )}
                    </button>

                    <div className="flex flex-col grow min-w-0">
                      <span className="font-['Inter'] text-[10px] font-black text-[#1D1D1F]/50 uppercase tracking-widest mb-1 truncate">
                        {task.tags?.[0] || 'TASK'}
                      </span>
                      <h3 className={`text-lg sm:text-xl font-black truncate transition-all duration-300 ${isCompleted ? 'text-[#1D1D1F]/40 line-through decoration-2' : 'text-[#1D1D1F]'}`}>
                        {task.name}
                      </h3>
                      <p className={`text-sm mt-1 font-bold tracking-tight ${isCompleted ? 'text-[#1D1D1F]/30' : 'text-[#1D1D1F]/60'}`}>
                        {task.startTime} 鈥?{task.endTime}
                      </p>
                    </div>
                  </div>
                </div>
              );
            })}

            <div className="flex sm:pl-[5.5rem] pt-6">
              <button 
                onClick={() => setEditingTask({ context: 'DAILY', task: { id: 'NEW', name: '', startTime: '12:00', endTime: '13:00', status: 'TODO', tags: ['NEW'] } })}
                className="w-full sm:w-auto px-8 py-5 bg-[#FFFFFF] border-[2px] border-dashed border-[#1D1D1F]/30 text-[#1D1D1F] font-black uppercase tracking-widest text-xs hover:border-[#1D1D1F] hover:bg-[#1D1D1F]/5 transition-all flex items-center justify-center gap-3 rounded-none"
              >
                <Plus size={18} strokeWidth={3} /> {t.createManual}
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

// --- View B: 姣忓懆妯℃澘绠＄悊鍣?(Weekly Editor) ---
const ViewWeekly = () => {
  const [activeDay, setActiveDay] = useState(1); 
  const { weeklyTemplate, currentDate, syncWeeklyTemplate, setView, setEditingTask, language } = useStore();
  const t = i18n[language];

  const daysEN = ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'];
  const daysZH = ['鍛ㄦ棩', '鍛ㄤ竴', '鍛ㄤ簩', '鍛ㄤ笁', '鍛ㄥ洓', '鍛ㄤ簲', '鍛ㄥ叚'];
  const displayDays = language === 'zh' ? daysZH : daysEN;
  const templateTasks = weeklyTemplate.days[activeDay] || [];

  return (
    <div className="pb-32 min-h-screen">
      <TopBar title={t.titleWeekly} />

      <main className="px-6 pt-8 max-w-2xl mx-auto space-y-12">
        <section>
          <p className="text-[#1D1D1F]/60 text-sm font-bold leading-relaxed mb-6">
            {t.weeklyDesc}
          </p>

          <div className="flex bg-[#1D1D1F]/5 p-1 overflow-x-auto no-scrollbar">
            {displayDays.map((day, idx) => (
              <button 
                key={idx} onClick={() => setActiveDay(idx)}
                className={`flex-1 min-w-[60px] py-4 font-black text-[10px] uppercase tracking-widest transition-colors ${activeDay === idx ? 'bg-[#1D1D1F] text-[#F9F9FB]' : 'text-[#1D1D1F]/60 hover:bg-[#1D1D1F]/10'}`}
              >
                {day}
              </button>
            ))}
          </div>
        </section>

        <button 
          onClick={() => { syncWeeklyTemplate(currentDate); setView('SCHEDULE'); }}
          className="w-full py-5 bg-[#72FF70] text-[#1D1D1F] font-black text-sm uppercase tracking-[0.2em] flex items-center justify-center gap-2 hover:brightness-95 transition-all"
        >
          <Download size={18} strokeWidth={3} /> {t.syncToToday} ({displayDays[new Date(currentDate).getDay()]})
        </button>

        <section className="space-y-4">
          <h3 className="font-['Inter'] text-xs font-black tracking-widest uppercase text-[#1D1D1F]/50 border-b-[2px] border-[#1D1D1F]/10 pb-4">
            {displayDays[activeDay]} {t.blueprint}
          </h3>

          {templateTasks.length === 0 ? (
            <div className="p-8 text-center text-[#1D1D1F]/40 font-bold uppercase tracking-widest text-xs border-[2px] border-dashed border-[#1D1D1F]/10">
              {t.noOps}
            </div>
          ) : (
            templateTasks.map((task) => (
              <div 
                key={task.id} 
                onClick={() => setEditingTask({ context: 'TEMPLATE', day: activeDay, task })}
                className="bg-[#FFFFFF] p-6 border-l-[3px] border-[#1D1D1F] flex justify-between items-start cursor-pointer hover:bg-[#1D1D1F]/5 transition-colors"
              >
                <div>
                  <span className="text-[10px] font-black text-[#1D1D1F]/50 uppercase tracking-widest block mb-1">{task.tags?.[0]}</span>
                  <h4 className="font-black text-lg uppercase tracking-tight text-[#1D1D1F]">{task.name}</h4>
                  <span className="text-xs font-bold text-[#1D1D1F]/60 mt-2 block">{task.startTime} 鈥?{task.endTime}</span>
                </div>
              </div>
            ))
          )}

          <button 
            onClick={() => setEditingTask({ context: 'TEMPLATE', day: activeDay, task: { id: 'NEW', name: '', startTime: '09:00', endTime: '10:00', status: 'TODO', tags: ['TEMPLATE'] } })}
            className="w-full py-5 border-[2px] border-[#1D1D1F] text-[#1D1D1F] font-black text-xs uppercase tracking-widest hover:bg-[#1D1D1F] hover:text-[#F9F9FB] transition-colors flex items-center justify-center gap-2"
          >
            <Plus size={16} strokeWidth={3} /> {t.addBlueprint}
          </button>
        </section>
      </main>
    </div>
  );
};

// --- View C: 鎴愭灉鏃ュ巻 (Achievement Calendar) ---
const ViewAchievements = () => {
  const { plans, language } = useStore();
  const t = i18n[language];

  const calendarData = useMemo(() => {
    const today = new Date();
    const data: { date: string; dayNum: number; isSlam: boolean; isToday: boolean }[] = [];
    let currentStreak = 0;
    let monthlySlams = 0;

    for (let i = 29; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(today.getDate() - i);
      const dateStr = d.toISOString().split('T')[0];
      const plan = plans[dateStr];
      const isSlam = plan?.isGrandSlam || false;
      data.push({ date: dateStr, dayNum: d.getDate(), isSlam, isToday: i === 0 });
    }

    for (let i = data.length - 1; i >= 0; i--) {
      if (data[i].isSlam) {
        currentStreak++;
      } else {
        if(i !== data.length - 1) break; 
      }
    }
    monthlySlams = data.filter(d => d.isSlam).length;

    return { grid: data, currentStreak, monthlySlams };
  }, [plans]);

  return (
    <div className="pb-32 min-h-screen">
      <TopBar title={t.titleAchievements} />
      <main className="px-6 pt-12 max-w-2xl mx-auto space-y-16">
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-[#FFFFFF] border-[2px] border-[#1D1D1F] p-6">
            <span className="font-['Inter'] text-[10px] font-black uppercase tracking-widest text-[#1D1D1F]/50 block mb-2">{t.slams30}</span>
            <div className="text-5xl font-black tracking-tighter text-[#1D1D1F]">{calendarData.monthlySlams}</div>
          </div>
          <div className="bg-[#1D1D1F] p-6 text-[#F9F9FB]">
            <span className="font-['Inter'] text-[10px] font-black uppercase tracking-widest text-[#F9F9FB]/50 block mb-2">{t.currentStreak}</span>
            <div className="text-5xl font-black tracking-tighter text-[#72FF70]">{calendarData.currentStreak}</div>
          </div>
        </div>

        <section className="space-y-6">
          <h3 className="font-['Inter'] text-xs font-black tracking-widest uppercase text-[#1D1D1F] border-b-[2px] border-[#1D1D1F]/10 pb-4">
            {t.heatmap}
          </h3>
          <div className="grid grid-cols-7 gap-2">
            {calendarData.grid.map((cell) => (
              <div 
                key={cell.date} 
                className={`aspect-square flex items-center justify-center text-sm font-bold transition-all
                  ${cell.isSlam ? 'bg-[#1D1D1F] text-[#72FF70] shadow-[4px_4px_0px_#72FF70]' : 'bg-[#1D1D1F]/5 text-[#1D1D1F]/40'}`}
              >
                {cell.dayNum}
              </div>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
};

// --- View D: PWA 寮曞涓庤缃?(Settings) ---
const ViewSettings = () => {
  const { language, setLanguage } = useStore();
  const t = i18n[language];
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
  const isAndroid = /android/i.test(navigator.userAgent);

  return (
    <div className="pb-32 min-h-screen">
      <TopBar title={t.titleSettings} />

      <main className="px-6 pt-12 max-w-2xl mx-auto space-y-12">

        {/* Language Switch */}
        <section className="space-y-6">
          <div className="space-y-2">
            <span className="font-['Inter'] uppercase tracking-widest text-[10px] font-black text-[#1D1D1F]/50">Locale</span>
            <h2 className="text-3xl font-black tracking-tighter text-[#1D1D1F] uppercase">{t.language}</h2>
          </div>
          <div 
            onClick={() => setLanguage(language === 'en' ? 'zh' : 'en')}
            className="bg-[#FFFFFF] p-6 border-[2px] border-[#1D1D1F] flex items-center justify-between cursor-pointer hover:bg-[#1D1D1F]/5 transition-colors"
          >
            <div className="flex items-center gap-4">
              <Globe size={24} />
              <span className="font-bold text-sm tracking-widest uppercase">{t.langLabel}</span>
            </div>
            <div className="text-xl font-black">{language === 'en' ? 'EN' : 'ZH'}</div>
          </div>
        </section>

        {/* PWA Install Guide */}
        <section className="space-y-6">
          <div className="space-y-2">
            <span className="font-['Inter'] uppercase tracking-widest text-[10px] font-black text-[#1D1D1F]/50">{t.install}</span>
            <h2 className="text-3xl font-black tracking-tighter text-[#1D1D1F] uppercase">{t.addWorkspace}</h2>
          </div>

          <div className="bg-[#FFFFFF] p-8 border-[2px] border-[#1D1D1F] space-y-8">
            {isIOS ? (
              <>
                <div className="flex items-start gap-6">
                  <div className="w-10 h-10 bg-[#1D1D1F] text-[#F9F9FB] flex items-center justify-center font-black">1</div>
                  <p className="text-[#1D1D1F] font-bold text-sm leading-relaxed mt-2">{t.iosStep1}</p>
                </div>
                <div className="flex items-start gap-6">
                  <div className="w-10 h-10 bg-[#1D1D1F] text-[#F9F9FB] flex items-center justify-center font-black">2</div>
                  <p className="text-[#1D1D1F] font-bold text-sm leading-relaxed mt-2">{t.iosStep2}</p>
                </div>
              </>
            ) : isAndroid ? (
              <>
                <div className="flex items-start gap-6">
                  <div className="w-10 h-10 bg-[#1D1D1F] text-[#F9F9FB] flex items-center justify-center font-black">1</div>
                  <p className="text-[#1D1D1F] font-bold text-sm leading-relaxed mt-2">{t.androidStep1}</p>
                </div>
                <div className="flex items-start gap-6">
                  <div className="w-10 h-10 bg-[#1D1D1F] text-[#F9F9FB] flex items-center justify-center font-black">2</div>
                  <p className="text-[#1D1D1F] font-bold text-sm leading-relaxed mt-2">{t.androidStep2}</p>
                </div>
              </>
            ) : (
              <p className="font-bold text-sm">{t.visitMsg}</p>
            )}
          </div>
        </section>

        {/* Danger Zone */}
        <section className="pt-8 border-t-[2px] border-[#1D1D1F]/10">
          <button 
            onClick={() => { localStorage.removeItem('planner-pwa-storage'); window.location.reload(); }}
            className="w-full p-6 bg-[#1D1D1F]/5 text-[#1D1D1F] font-black uppercase tracking-widest text-xs hover:bg-[#1D1D1F] hover:text-[#ba1a1a] transition-colors flex items-center justify-center gap-3"
          >
            <Trash2 size={18} /> {t.clearStorage}
          </button>
        </section>
      </main>
    </div>
  );
};

// --- 浠诲姟缂栬緫/鏂板缓闈㈡澘 (Modal) ---
const TaskEditorModal = () => {
  const { 
    editingTask, setEditingTask, currentDate, language,
    addTask, updateTask, deleteTask,
    addTemplateTask, updateTemplateTask, deleteTemplateTask
  } = useStore();

  const [form, setForm] = useState<Task | null>(editingTask?.task || null);

  useEffect(() => { setForm(editingTask?.task || null); }, [editingTask]);

  if (!editingTask || !form) return null;

  const t = i18n[language];
  const isNew = form.id === 'NEW';
  const isTemplate = editingTask.context === 'TEMPLATE';

  const handleSave = () => {
    if (isTemplate) {
      isNew ? addTemplateTask(editingTask.day!, form) : updateTemplateTask(editingTask.day!, form);
    } else {
      isNew ? addTask(currentDate, form) : updateTask(currentDate, form);
    }
  };

  const handleDelete = () => {
    if (isTemplate) {
      deleteTemplateTask(editingTask.day!, form.id);
    } else {
      deleteTask(currentDate, form.id);
    }
  };

  return (
    <AnimatePresence>
      <motion.div 
        initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }} transition={{ type: 'spring', damping: 25, stiffness: 200 }}
        className="fixed inset-0 z-50 bg-[#F9F9FB] flex flex-col"
      >
        <header className="flex justify-between items-center px-6 h-20 bg-[#F9F9FB] border-b-[2px] border-[#1D1D1F] shrink-0">
          <button onClick={() => setEditingTask(null)} className="font-black uppercase text-xs tracking-widest text-[#1D1D1F]/50 hover:text-[#1D1D1F]">{t.cancel}</button>
          <h1 className="font-black uppercase text-sm tracking-tight text-[#1D1D1F]">{isNew ? t.newTask : t.editTask} {isTemplate && '(Template)'}</h1>
          <button onClick={handleSave} className="font-black uppercase text-xs tracking-widest bg-[#1D1D1F] text-[#F9F9FB] px-6 py-3 hover:bg-[#72FF70] hover:text-[#1D1D1F] transition-colors">
            {t.save}
          </button>
        </header>

        <main className="flex-1 overflow-y-auto pt-10 pb-32 px-6 max-w-2xl mx-auto w-full space-y-12">
          <section className="space-y-2">
            <label className="block text-[10px] font-black tracking-widest uppercase text-[#1D1D1F]/50">{t.taskIdentity}</label>
            <input 
              type="text" value={form.name} onChange={e => setForm({...form, name: e.target.value})}
              className="w-full bg-transparent border-t-0 border-x-0 border-b-[3px] border-[#1D1D1F] text-3xl font-black tracking-tighter py-3 focus:ring-0 focus:outline-none placeholder:text-[#1D1D1F]/20 rounded-none"
              placeholder={t.taskIdentity} autoFocus
            />
          </section>

          <section className="grid grid-cols-2 gap-4">
            <div className="bg-[#FFFFFF] p-6 border-[2px] border-[#1D1D1F]">
              <label className="block text-[10px] font-black tracking-widest uppercase text-[#1D1D1F]/50 mb-4">{t.startBlock}</label>
              <input 
                type="time" value={form.startTime} onChange={e => setForm({...form, startTime: e.target.value})}
                className="text-4xl font-black tracking-tighter bg-transparent border-none p-0 focus:ring-0 w-full" 
              />
            </div>
            <div className="bg-[#1D1D1F]/5 p-6 border-[2px] border-transparent">
              <label className="block text-[10px] font-black tracking-widest uppercase text-[#1D1D1F]/50 mb-4">{t.endBlock}</label>
              <input 
                type="time" value={form.endTime} onChange={e => setForm({...form, endTime: e.target.value})}
                className="text-4xl font-black tracking-tighter bg-transparent border-none p-0 focus:ring-0 w-full" 
              />
            </div>
          </section>

          {!isNew && (
            <section className="pt-12 mt-auto">
              <button 
                onClick={handleDelete}
                className="w-full py-6 bg-transparent border-[2px] border-[#ba1a1a] text-[#ba1a1a] font-black tracking-[0.2em] uppercase text-xs hover:bg-[#ba1a1a] hover:text-white transition-colors flex items-center justify-center gap-3"
              >
                <Trash2 size={18} strokeWidth={3} /> {t.terminate}
              </button>
            </section>
          )}
        </main>
      </motion.div>
    </AnimatePresence>
  );
};

// ==========================================
// 4. MAIN ENTRY (App Root)
// ==========================================
export default function App() {
  const { currentView, showGrandSlamEffect } = useStore();

  useEffect(() => {
    const fontLink = document.createElement('link');
    fontLink.href = 'https://fonts.googleapis.com/css2?family=Inter:wght@400;700;900&display=swap';
    fontLink.rel = 'stylesheet';
    document.head.appendChild(fontLink);
    return () => document.head.removeChild(fontLink);
  }, []);

  return (
    <div className="min-h-screen bg-[#F9F9FB] text-[#1D1D1F] font-['Inter'] selection:bg-[#72FF70] selection:text-[#1D1D1F] relative overflow-hidden">
      <AnimatePresence mode="wait">
        <motion.div
          key={currentView}
          initial={{ opacity: 0, y: 5 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -5 }}
          transition={{ duration: 0.2 }}
        >
          {currentView === 'SCHEDULE' && <ViewSchedule />}
          {currentView === 'WEEKLY' && <ViewWeekly />}
          {currentView === 'ACHIEVEMENTS' && <ViewAchievements />}
          {currentView === 'SETTINGS' && <ViewSettings />}
        </motion.div>
      </AnimatePresence>

      <BottomNav />
      <TaskEditorModal />

      <AnimatePresence>
        {showGrandSlamEffect && <GrandSlamEffect />}
      </AnimatePresence>
    </div>
  );
}
